46	/// Invoke a handbook tabtarget with no arguments and return Pass iff exit 0.
47	/// Writes stdout/stderr traces to the per-case directory for diagnostic review.
48	fn rbtdrf_hb_render(dir: &Path, colophon: &str, label: &str) -> rbtdre_Verdict {
49	    let root = match std::env::current_dir() {
50	        Ok(r) => r,
51	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot get cwd: {}", e)),
52	    };
53	
54	    let tt = match rbtdri_find_tabtarget_global(&root, colophon) {
55	        Ok(p) => p,
56	        Err(e) => return rbtdre_Verdict::Fail(e),
57	    };
58	
59	    let output = match Command::new(&tt).current_dir(&root).output() {
60	        Ok(o) => o,
61	        Err(e) => {
62	            return rbtdre_Verdict::Fail(format!(
63	                "{}: failed to run {}: {}",
64	                label,
65	                tt.display(),
66	                e
67	            ));
68	        }
69	    };
70	
71	    let code = output.status.code().unwrap_or(-1);
72	    let _ = std::fs::write(dir.join(format!("{}-stdout.txt", label)), &output.stdout);
73	    let _ = std::fs::write(dir.join(format!("{}-stderr.txt", label)), &output.stderr);
74	
75	    if code != 0 {
76	        return rbtdre_Verdict::Fail(format!(
77	            "{}: {} exited {} — {}",
78	            label,
79	            colophon,
80	            code,
81	            String::from_utf8_lossy(&output.stderr),
82	        ));
83	    }
84	    rbtdre_Verdict::Pass
85	}
