208	/// Invoke ifrit inside the bottle via bark, saving stdout/stderr to case dir.
209	fn rbtdrc_invoke_ifrit(
210	    ctx: &mut rbtdri_Context,
211	    attack: &str,
212	    dir: &Path,
213	) -> rbtdre_Verdict {
214	    let result = match rbtdri_invoke(ctx, RBTDRM_COLOPHON_BARK, &[RBTDRC_IFRIT_BINARY, attack]) {
215	        Ok(r) => r,
216	        Err(e) => return rbtdre_Verdict::Fail(format!("bark invocation error: {}", e)),
217	    };
218	    let _ = std::fs::write(dir.join("bark-stdout.txt"), &result.stdout);
219	    let _ = std::fs::write(dir.join("bark-stderr.txt"), &result.stderr);
220	    rbtdri_parse_ifrit_verdict(&result.stdout, result.exit_code)
221	}
